import pRetry from 'p-retry';
const result = await pRetry(() => openai.chat.completions.create(params), {
  retries: 5,
  factor: 2,
  minTimeout: 1000,
  maxTimeout: 30000,
  onFailedAttempt: (err) => logger.warn({ attempt: err.attemptNumber, retriesLeft: err.retriesLeft }, 'AI API retry')
});

